# Base animal module providing abstract base class
@abstract
class Animal:
    name: str

    def __init__(self, name: str):
        self.name = name

    @abstract
    def speak(self) -> str:
        ...

    @virtual
    def describe(self) -> str:
        return f"Animal named {self.name}"

